import {
  useMutation,
  useQueryClient,
} from '@tanstack/react-query'

import { queryKeys } from '../query/query-keys'
import { logout } from './auth-api'
import { getRefreshToken } from './token-storage'
import { useAuthStore } from '../../store/auth.store'

export function useLogout() {
  const queryClient = useQueryClient()
  const clearSession =
    useAuthStore(
      (state) => state.clearSession,
    )

  return useMutation({
    mutationFn: () =>
      logout(getRefreshToken()),
    onSettled: async () => {
      clearSession()

      await queryClient.invalidateQueries({
        queryKey: queryKeys.auth.all,
      })
    },
  })
}

import { useCurrentUser } from './useCurrentUser'

export function usePermission(
  permission: string,
) {
  const { data: user } =
    useCurrentUser()

  return Boolean(
    user?.permissions?.includes(
      permission,
    ),
  )
}

import {
  Loader2,
  RotateCcw,
} from 'lucide-react'

import { Button } from '../../components/ui/Button'
import { JobStatusBadge } from './JobStatusBadge'
import { RetryStatusBadge } from './RetryStatusBadge'

import type {
  BackgroundJob,
} from './job.types'

interface BackgroundTaskStatusProps {
  job: BackgroundJob
  retrying?: boolean
  onRetry?: (id: string) => void
}

export function BackgroundTaskStatus({
  job,
  retrying = false,
  onRetry,
}: BackgroundTaskStatusProps) {
  const processing =
    job.status === 'RUNNING' ||
    job.status === 'QUEUED' ||
    job.status === 'RETRYING'

return (
    <div className="rounded-lg border border-zinc-800 bg-zinc-900 p-4">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="min-w-0">
          <div className="flex flex-wrap items-center gap-2">
            <p className="truncate text-sm font-medium text-white">
              {job.name}
            </p>

            <JobStatusBadge status={job.status} />
            <RetryStatusBadge
              retryCount={job.retryCount}
              maxRetries={job.maxRetries}
            />
          </div>

          <p className="mt-1 text-xs text-zinc-500">
            {job.queue} · {job.id}
          </p>
        </div>

        {processing ? (
          <Loader2 className="h-5 w-5 animate-spin text-cyan-400" />
        ) : null}

        {onRetry &&
        ['FAILED', 'DEAD_LETTER'].includes(job.status) ? (
          <Button
            type="button"
            variant="secondary"
            disabled={retrying}
            onClick={() => onRetry(job.id)}
          >
            <span className="inline-flex items-center gap-2">
              <RotateCcw className="h-4 w-4" />
              Retry
            </span>
          </Button>
        ) : null}
      </div>

      {job.lastError ? (
        <p className="mt-3 rounded-md bg-red-500/10 px-3 py-2 text-xs text-red-200">
          {job.lastError}
        </p>
      ) : null}
    </div>
  )
}

import clsx from 'clsx'

import type {
  BackgroundJobStatus,
} from './job.types'

interface JobStatusBadgeProps {
  status: BackgroundJobStatus | string
}

const statusClassName: Record<string, string> = {
  QUEUED: 'bg-zinc-700 text-zinc-200',
  RUNNING: 'bg-cyan-500/20 text-cyan-300',
  COMPLETED: 'bg-emerald-500/20 text-emerald-300',
  FAILED: 'bg-red-500/20 text-red-300',
  RETRYING: 'bg-amber-500/20 text-amber-300',
  CANCELLED: 'bg-zinc-600 text-zinc-200',
  DEAD_LETTER: 'bg-red-900/70 text-red-200',
}

export function JobStatusBadge({
  status,
}: JobStatusBadgeProps) {
  return (
    <span
      className={clsx(
        'inline-flex items-center rounded-md px-2 py-1 text-xs font-medium',
        statusClassName[status] ??
          'bg-zinc-700 text-zinc-200',
      )}
    >
      {status.replaceAll('_', ' ')}
    </span>
  )
}

interface RetryStatusBadgeProps {
  retryCount: number
  maxRetries: number
}

export function RetryStatusBadge({
  retryCount,
  maxRetries,
}: RetryStatusBadgeProps) {
  const exhausted = retryCount >= maxRetries

  return (
    <span
      className={`inline-flex items-center rounded-md px-2 py-1 text-xs font-medium ${
        exhausted
          ? 'bg-red-500/20 text-red-300'
          : retryCount > 0
            ? 'bg-amber-500/20 text-amber-300'
            : 'bg-zinc-800 text-zinc-300'
      }`}
    >
      Retry {retryCount}/{maxRetries}
    </span>
  )
}

