  useState,
} from 'react'

import {
  StatusBadge,
} from '../../components/ui-system'

interface SlowQueryWarningProps {
  label: string
  startedAt?: number
  thresholdMs?: number
  loading?: boolean
}

export function SlowQueryWarning({
  label,
  startedAt,
  thresholdMs = 1500,
  loading,
}: SlowQueryWarningProps) {
  const [slowStartedAt, setSlowStartedAt] =
    useState<number>()

  useEffect(() => {
    if (!loading || !startedAt) {
      return
    }

    const timeoutId = window.setTimeout(
      () => setSlowStartedAt(startedAt),
      thresholdMs,
    )

    return () =>
      window.clearTimeout(timeoutId)
  }, [loading, startedAt, thresholdMs])

  const slow =
    Boolean(loading) &&
    slowStartedAt === startedAt

  if (!slow) {
    return null
  }

  return (
    <StatusBadge tone="warning">
      {`${label} slow`}
    </StatusBadge>
  )
}

export class EventBatcher<T> {
  private queue: T[] = []
  private timeoutId?: number
  private readonly flushDelayMs: number
  private readonly onFlush: (items: T[]) => void

  constructor(
    flushDelayMs: number,
    onFlush: (items: T[]) => void,
  ) {
    this.flushDelayMs = flushDelayMs
    this.onFlush = onFlush
  }

  push(item: T) {
    this.queue.push(item)

    if (this.timeoutId) {
      return
    }

    this.timeoutId = window.setTimeout(
      () => this.flush(),
      this.flushDelayMs,
    )
  }

  flush() {
    if (this.timeoutId) {
      window.clearTimeout(this.timeoutId)
      this.timeoutId = undefined
    }

    if (this.queue.length === 0) {
      return
    }

    const items = this.queue
    this.queue = []
    this.onFlush(items)
  }

  clear() {
    if (this.timeoutId) {
      window.clearTimeout(this.timeoutId)
      this.timeoutId = undefined
    }

    this.queue = []
  }
}

