import {
  AlertTriangle,
  CheckCircle2,
  Circle,
  Clock3,
  XCircle,
} from 'lucide-react'

import type {
  WorkflowInstance,
  WorkflowStep,
} from './workflow.types'

interface WorkflowTimelineProps {
  instance: WorkflowInstance
}

function stepState(
  instance: WorkflowInstance,
  step: WorkflowStep,
) {
  if (instance.currentStepId === step.id) {
    return 'current'
  }

  const approved = instance.actions.some(
    (action) =>
      action.stepId === step.id &&
      ['APPROVE', 'MOVE_NEXT', 'COMPLETE'].includes(
        action.type,
      ),
  )

  if (approved) {
    return 'done'
  }

  return 'pending'
}

export function WorkflowTimeline({
  instance,
}: WorkflowTimelineProps) {
  return (
    <ol className="space-y-3">
      {instance.definition.steps.map((step) => {
        const state = stepState(instance, step)
        const Icon =
          state === 'done'
            ? CheckCircle2
            : state === 'current'
              ? Clock3
              : Circle

        return (
          <li
            key={step.id}
            className="flex gap-3 rounded-lg border border-zinc-800 bg-zinc-900/60 p-3"
          >
            <Icon
              className={
                state === 'done'
                  ? 'mt-0.5 h-5 w-5 text-emerald-400'
                  : state === 'current'
                    ? 'mt-0.5 h-5 w-5 text-cyan-400'
                    : 'mt-0.5 h-5 w-5 text-zinc-500'
              }
            />

export function WorkflowActivityTimeline({
  instance,
}: WorkflowTimelineProps) {
  return (
    <ol className="space-y-3">
      {instance.actions.map((action) => {
        const Icon =
          action.type === 'REJECT'
            ? XCircle
            : action.type === 'ESCALATE'
              ? AlertTriangle
              : CheckCircle2

