import type {
  AnalyticsAlert,
  AnalyticsMetric,
} from '../analytics-ui'
import type {
  CommandEvent,
  CommandSeverity,
} from './command-center.types'

export function severityTone(
  severity?: CommandSeverity | string,
) {
  if (
    severity === 'critical' ||
    severity === 'CRITICAL'
  ) {
    return 'danger' as const
  }

  if (
    severity === 'warning' ||
    severity === 'WARNING'
  ) {
    return 'warning' as const
  }

  if (
    severity === 'info' ||
    severity === 'INFO'
  ) {
    return 'info' as const
  }

  return 'success' as const
}

export function metricSeverity(
  metric?: AnalyticsMetric,
): CommandSeverity {
  if (!metric) {
    return 'normal'
  }

  if (
    metric.threshold !== undefined &&
    metric.threshold !== null
  ) {
    if (
      metric.key === 'qc.pass.rate' &&
      metric.value < metric.threshold
    ) {
      return 'critical'
    }

    if (metric.value > metric.threshold) {
      return 'warning'
    }
  }

  return 'normal'
}

export function alertToEvent(
  alert: AnalyticsAlert,
): CommandEvent {
  return {
    id: alert.id,
    event: alert.key,
    domain: alert.domain,
    message: alert.message,
    severity:
      alert.severity === 'CRITICAL'
        ? 'critical'
        : alert.severity === 'WARNING'
          ? 'warning'
          : 'info',
    occurredAt: alert.createdAt,
  }
}

export function formatMetricValue(
  value: number | undefined,
  unit?: string | null,
) {
  return `${value ?? 0}${unit ?? ''}`
}

import {
  useEffect,
  useState,
} from 'react'

import {
  EventBatcher,
  isPageVisible,
} from '../../lib/performance'
import { socketClient } from '../../lib/realtime/socket-client'

import type {
  RealtimeEventPayload,
} from '../../lib/realtime/socket-client'
import type {
  CommandEvent,
  CommandSeverity,
} from './command-center.types'

export function useCommandCenterEvents() {
  const [events, setEvents] = useState<
    CommandEvent[]
  >([])

  useEffect(() => {
    const batcher =
      new EventBatcher<CommandEvent>(
        300,
        (items) => {
          if (!isPageVisible()) {
            return
          }

          setEvents((current) => [
            ...items,
            ...current,
          ].slice(0, 30))
        },
      )

    const handleEvent = (
      payload: RealtimeEventPayload,
    ) => {
      if (!payload.event) {
        return
      }

      const domain =
        payload.event.split('.')[0] ??
        'system'
      const severity: CommandSeverity =
        payload.event.includes('failed') ||
        payload.event.includes('rework') ||
        payload.event.includes('threshold')
          ? 'warning'
          : 'info'

      batcher.push(
        {
          id: `${payload.event}-${payload.occurredAt ?? Date.now()}`,
          event: payload.event,
          domain,
          message: payload.event.replaceAll(
            '.',
            ' ',
          ),
          severity,
          occurredAt:
            payload.occurredAt ??
            new Date().toISOString(),
        },
      )
    }

    socketClient.on(
      'domain.event',
      handleEvent,
    )

    return () => {
      socketClient.off(
        'domain.event',
        handleEvent,
      )
      batcher.clear()
    }
  }, [])

  return events
}

