} from './production.types'

type ProductionListResult =
  | ProductionOrder[]
  | PaginatedProductionResponse<ProductionOrder>

export async function getProductionOrders(
  params?: ProductionListParams,
) {
  const response =
    await api.get<ProductionListResult>(
      '/production',
      { params },
    )

  return response.data
}

export async function getProductionOrder(
  id: string,
) {
  const response =
    await api.get<ProductionOrder>(
      `/production/${id}`,
    )

  return response.data
}

export async function getProductionMetrics() {
  const response =
    await api.get<ProductionMetrics>(
      '/production/metrics',
    )

  return response.data
}

export async function getWorkCenters() {
  const response =
    await api.get<WorkCenter[]>(
      '/production/work-centers',
    )

  return response.data
}

export async function getMachines() {
  const response =
    await api.get<Machine[]>(
      '/production/machines',
    )

  return response.data
}

export async function startProductionOrder(
  id: string,
) {
  const response =
    await api.post<ProductionOrder>(
      `/production/${id}/start`,
      {},
    )

  return response.data
}

export async function completeProductionStage(
  stageId: string,
  payload: {
    message?: string
    qualityStatus?: string
    quantity?: number
    attachmentIds?: string[]
  } = {},
) {
  const response =
    await api.post<ProductionOrder>(
      `/production/stages/${stageId}/complete`,
      payload,
    )

  return response.data
}

import {
  useMutation,
  useQuery,
  useQueryClient,
} from '@tanstack/react-query'

import {
  invalidateProduction,
} from '../../lib/query/invalidation'
import { queryKeys } from '../../lib/query/query-keys'
import {
  completeProductionStage,
  getMachines,
  getProductionMetrics,
  getProductionOrder,
  getProductionOrders,
  getWorkCenters,
  startProductionOrder,
} from './production-api'

import type {
  ProductionListParams,
} from './production.types'

export function useProductionOrdersQuery(
  params?: ProductionListParams,
) {
  return useQuery({
    queryKey:
      queryKeys.production.orderList(params),
    queryFn: () => getProductionOrders(params),
  })
}

export function useProductionOrderQuery(
  id?: string,
) {
  return useQuery({
    queryKey: id
      ? queryKeys.production.order(id)
      : queryKeys.production.order('pending'),
    queryFn: () => getProductionOrder(id ?? ''),
    enabled: Boolean(id),
  })
}

export function useProductionMetricsQuery() {
  return useQuery({
    queryKey: queryKeys.production.metrics(),
    queryFn: getProductionMetrics,
  })
}

export function useWorkCentersQuery() {
  return useQuery({
    queryKey: queryKeys.production.workCenters(),
    queryFn: getWorkCenters,
  })
}

export function useMachinesQuery() {
  return useQuery({
    queryKey: queryKeys.production.machines(),
    queryFn: getMachines,
  })
}

export function useStartProductionOrderMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: startProductionOrder,
    onSuccess: () =>
      invalidateProduction(queryClient),
  })
}

export function useCompleteProductionStageMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({
      stageId,
      payload,
    }: {
      stageId: string
      payload?: Parameters<
        typeof completeProductionStage
      >[1]
    }) =>
      completeProductionStage(
        stageId,
        payload,
      ),
    onSuccess: () =>
      invalidateProduction(queryClient),
  })
}

export function asProductionList<T>(
  value:
    | T[]
    | {
        data: T[]
      }
    | undefined,
) {
  if (!value) return []

  return Array.isArray(value) ? value : value.data
}

export function stageTone(status: string) {
  if (status === 'COMPLETED') return 'success'
  if (status === 'IN_PROGRESS') return 'info'
  if (status === 'BLOCKED') return 'danger'
  if (status === 'READY') return 'warning'

  return 'neutral'
}

export interface ProductionMetrics {
  totalOrders: number
  inProgress: number
  delayed: number
  completed: number
  completionRate: number
  throughput: number
