interface YardViewportProps {
  world: YardWorldModel
  cranes?: Crane[]
  movements?: YardMovement[]
  compact?: boolean
  className?: string
}

export function YardViewport({
  world,
  cranes,
  movements,
  compact,
  className,
}: YardViewportProps)

{
  const {
    containerRef,
    viewport,
    selection,
    visibleSlots,
    setSelectedSlot,
    updateHoveredSlot,
    handlers,
  } = useYardPixiViewport(world)
  const pixiPerformance =
    usePerformanceMonitor()

  const layerProps = useMemo(
    () => ({
      world,
      viewport,
      selection,
      visibleSlots,
      onSelectSlot: setSelectedSlot,
      onHoverSlot: updateHoveredSlot,
    }),
    [
      selection,
      setSelectedSlot,
      updateHoveredSlot,
      viewport,
      visibleSlots,
      world,
    ],
  )

  const layers = sortYardLayers(
    defaultYardLayers,
  ).filter((layer) =>
    shouldRenderLayer(layer, layerProps),
  )

  return (
    <div
      ref={containerRef}
      className={clsx(
        'relative overflow-hidden rounded-xl border border-zinc-800 bg-zinc-950',
        compact ? 'h-[360px]' : 'h-[560px]',
        className,
      )}
      {...handlers}
    >
      <Application
        width={viewport.width}
        height={viewport.height}
        antialias
        autoDensity
        backgroundAlpha={0}
        resolution={
          window.devicePixelRatio || 1
        }
      >
        <pixiContainer
          x={viewport.offsetX}
          y={viewport.offsetY}
          scale={viewport.scale}
          sortableChildren
        >
          {layers.map((layer) =>

{
            if (layer.id === YardLayerId.Grid) {
              return (
                <pixiContainer
                  key={layer.id}
                  zIndex={layer.zIndex}
                >
                  <YardGridLayer {...layerProps} />
                </pixiContainer>
              )
            }

            if (layer.id === YardLayerId.Heatmap) {
              return (
                <pixiContainer
                  key={layer.id}
                  zIndex={layer.zIndex}
                >
                  <YardHeatmapLayer
                    {...layerProps}
                  />
                </pixiContainer>
              )
            }

            if (layer.id === YardLayerId.Slots) {
              return (
                <pixiContainer
                  key={layer.id}
                  zIndex={layer.zIndex}
                >
                  <YardSlotLayer
                    {...layerProps}
                  />
                </pixiContainer>
              )
            }

            if (
              layer.id === YardLayerId.Movement
            ) {
              return (
                <pixiContainer
                  key={layer.id}
                  zIndex={layer.zIndex}
                >
                  <YardMovementLayer
                    {...layerProps}
                    movements={movements}
                  />
                </pixiContainer>
              )
            }

if (layer.id === YardLayerId.Crane) {
              return (
                <pixiContainer
                  key={layer.id}
                  zIndex={layer.zIndex}
                >
                  <CraneLayer
                    {...layerProps}
                    cranes={cranes}
                  />
                </pixiContainer>
              )
            }

            return null
          })}
        </pixiContainer>
      </Application>

      <SelectionOverlay
        selection={selection}
        slots={visibleSlots}
        viewport={viewport}
      />
      <RealtimeMovementPulse
        movements={movements}
        slots={world.slots}
        viewport={viewport}
      />
      <YardMinimap
        world={world}
        viewport={viewport}
      />

      <div className="pointer-events-none absolute left-4 top-4 z-20 rounded-lg border border-zinc-800 bg-zinc-950/80 px-3 py-2 text-xs text-zinc-300 backdrop-blur">
        <span className="font-medium text-white">
          {visibleSlots.length.toLocaleString()}
        </span>{' '}
        visible /{' '}
        {world.slots.length.toLocaleString()} slots
        <span className="ml-2 text-zinc-500">
          {pixiPerformance.fps || 0} fps
        </span>
      </div>
    </div>
  )
}

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react'
import type {
  MouseEvent,
  PointerEvent,
  WheelEvent,
} from 'react'

import {
  hitTestSlot,
  panViewport,
  zoomViewportAtPoint,
} from '../renderer/interaction-controller'
import {
  createInitialViewport,
  getVisibleSlots,
  screenToWorld,
} from '../renderer/viewport-manager'

import type {
  YardSelectionState,
  YardViewportState,
  YardWorldModel,
  YardWorldSlot,
} from '../renderer/yard-visualization.types'

export function useYardPixiViewport(
  world: YardWorldModel,
)

{
  const containerRef =
    useRef<HTMLDivElement | null>(null)
  const draggingRef = useRef(false)
  const [selection, setSelection] =
    useState<YardSelectionState>({})
  const [viewport, setViewport] =
    useState<YardViewportState>(() =>
      createInitialViewport(900, 520, world),
    )

  useEffect(() => {
    const element = containerRef.current

    if (!element) {
      return
    }

    const observer = new ResizeObserver(
      ([entry]) => {
        const width =
          entry.contentRect.width || 900
        const height =
          entry.contentRect.height || 520

        setViewport(
          createInitialViewport(
            width,
            height,
            world,
          ),
        )
      },
    )

    observer.observe(element)

    return () => observer.disconnect()
  }, [world])

  const visibleSlots = useMemo(
    () =>
      getVisibleSlots(
        world.slots,
        viewport,
      ),
    [viewport, world.slots],
  )

  const setSelectedSlot =
    useCallback((slot?: YardWorldSlot) => {
      setSelection((current) => ({
        ...current,
        selectedSlotId: slot?.id,
      }))
    }, [])

  const updateHoveredSlot =
    useCallback((slot?: YardWorldSlot) => {
      setSelection((current) => ({
        ...current,
        hoveredSlotId: slot?.id,
      }))
    }, [])

const getLocalPoint = useCallback(
    (
      event:
        | PointerEvent
        | WheelEvent
        | MouseEvent,
    ) => {
      const bounds =
        containerRef.current?.getBoundingClientRect()

      return {
        x: event.clientX - (bounds?.left ?? 0),
        y: event.clientY - (bounds?.top ?? 0),
      }
    },
    [],
  )

  const handleWheel = useCallback(
    (event: WheelEvent) => {
      event.preventDefault()
      const point = getLocalPoint(event)

      setViewport((current) =>
        zoomViewportAtPoint(
          current,
          point.x,
          point.y,
          event.deltaY,
        ),
      )
    },
    [getLocalPoint],
  )

  const handlePointerDown = useCallback(
    (event: PointerEvent) => {
      draggingRef.current = true
      event.currentTarget.setPointerCapture(
        event.pointerId,
      )
    },
    [],
  )

const handlePointerMove = useCallback(
    (event: PointerEvent) => {
      const point = getLocalPoint(event)
      const worldPoint = screenToWorld(
        point.x,
        point.y,
        viewport,
      )

      updateHoveredSlot(
        hitTestSlot(
          visibleSlots,
          worldPoint.x,
          worldPoint.y,
        ),
      )

      if (!draggingRef.current) {
        return
      }

      setViewport((current) =>
        panViewport(
          current,
          event.movementX,
          event.movementY,
        ),
      )
    },
    [
      getLocalPoint,
      updateHoveredSlot,
      viewport,
      visibleSlots,
    ],
  )

  const handlePointerUp = useCallback(
    (event: PointerEvent) => {
      draggingRef.current = false
      event.currentTarget.releasePointerCapture(
        event.pointerId,
      )
    },
    [],
  )

  const handleClick = useCallback(
    (event: MouseEvent) => {
      const point = getLocalPoint(event)
      const worldPoint = screenToWorld(
        point.x,
        point.y,
        viewport,
      )

      setSelectedSlot(
        hitTestSlot(
          visibleSlots,
          worldPoint.x,
          worldPoint.y,
        ),
      )
    },
    [
      getLocalPoint,
      setSelectedSlot,
      viewport,
      visibleSlots,
    ],
  )

import {
  useCallback,
} from 'react'
import type {
  Graphics,
} from 'pixi.js'

import type {
  Crane,
} from '../../yard-ui'
import type {
  YardRendererLayerProps,
} from '../renderer/yard-visualization.types'

interface CraneLayerProps
  extends YardRendererLayerProps {
  cranes?: Crane[]
}

function craneColor(status: Crane['status']) {
  if (status === 'OFFLINE') {
    return 0x64748b
  }

  if (status === 'MAINTENANCE') {
    return 0xf97316
  }

  if (status === 'ASSIGNED') {
    return 0x38bdf8
  }

  return 0x22c55e
}

export function CraneLayer({
  cranes = [],
}: CraneLayerProps) {
  const draw = useCallback(
    (graphics: Graphics) => {
      graphics.clear()

      for (const crane of cranes) {
        graphics.setFillStyle({
          color: craneColor(crane.status),
          alpha: 0.9,
        })
        graphics.circle(
          crane.currentX,
          crane.currentY,
          8,
        )
        graphics.fill()

        graphics.setStrokeStyle({
          color: 0xe2e8f0,
          alpha: 0.52,
          width: 2,
        })
        graphics.circle(
          crane.currentX,
          crane.currentY,
          14,
        )
        graphics.stroke()
      }
    },
    [cranes],
  )

  return <pixiGraphics draw={draw} />
}

import {
  useCallback,
} from 'react'
import type {
  Graphics,
} from 'pixi.js'

import type {
  YardRendererLayerProps,
} from '../renderer/yard-visualization.types'

export function YardGridLayer({
  world,
  viewport,
}: YardRendererLayerProps) {
  const draw = useCallback(
    (graphics: Graphics) => {
      graphics.clear()

      const gridSize = 48
      const left = world.bounds.minX - 200
      const top = world.bounds.minY - 200
      const right = world.bounds.maxX + 200
      const bottom = world.bounds.maxY + 200

      graphics.setStrokeStyle({
        color: 0x334155,
        alpha: viewport.scale > 0.45 ? 0.28 : 0.12,
        width: 1,
      })

      for (
        let x =
          Math.floor(left / gridSize) *
          gridSize;
        x <= right;
        x += gridSize
      ) {
        graphics.moveTo(x, top)
        graphics.lineTo(x, bottom)
      }

      for (
        let y =
          Math.floor(top / gridSize) *
          gridSize;
        y <= bottom;
        y += gridSize
      ) {
        graphics.moveTo(left, y)
        graphics.lineTo(right, y)
      }

      graphics.stroke()

      graphics.setStrokeStyle({
        color: 0x64748b,
        alpha: 0.35,
        width: 2,
      })

      for (const zone of world.zones) {
        graphics.rect(
          zone.x,
          zone.y,
          zone.width,
          zone.height,
        )
      }

      graphics.stroke()
    },
    [viewport.scale, world],
  )

  return <pixiGraphics draw={draw} />
