export const YardLayerId = {
  Grid: 'grid',
  Heatmap: 'heatmap',
  Slots: 'slots',
  Movement: 'movement',
  Crane: 'crane',
  Selection: 'selection',
} as const

export type YardLayerId =
  (typeof YardLayerId)[keyof typeof YardLayerId]

export interface YardLayerDefinition {
  id: YardLayerId
  zIndex: number
  visible: boolean
  renderWhenEmpty?: boolean
}

export const defaultYardLayers: YardLayerDefinition[] =
  [
    {
      id: YardLayerId.Grid,
      zIndex: 10,
      visible: true,
      renderWhenEmpty: true,
    },
    {
      id: YardLayerId.Heatmap,
      zIndex: 20,
      visible: true,
    },
    {
      id: YardLayerId.Slots,
      zIndex: 30,
      visible: true,
    },
    {
      id: YardLayerId.Movement,
      zIndex: 40,
      visible: true,
    },
    {
      id: YardLayerId.Crane,
      zIndex: 50,
      visible: true,
    },
    {
      id: YardLayerId.Selection,
      zIndex: 60,
      visible: true,
    },
  ]

export function sortYardLayers(
  layers: YardLayerDefinition[] =
    defaultYardLayers,
) {
  return [...layers].sort(
    (left, right) => left.zIndex - right.zIndex,
  )
}

export function shouldRenderLayer(
  layer: YardLayerDefinition,
  props: YardRendererLayerProps,
) {
  return (
    layer.visible &&
    (layer.renderWhenEmpty ||
      props.world.slots.length > 0)
  )
}

import type {
  YardViewportState,
  YardWorldModel,
  YardWorldSlot,
} from './yard-visualization.types'

export function createInitialViewport(
  width: number,
  height: number,
  world: YardWorldModel,
): YardViewportState {
  const scale = Math.min(
    width / Math.max(world.bounds.width, 1),
    height / Math.max(world.bounds.height, 1),
    1,
  )

  return {
    scale: Math.max(scale * 0.9, 0.2),
    offsetX: 32 - world.bounds.minX * scale,
    offsetY: 32 - world.bounds.minY * scale,
    width,
    height,
  }
}

export function worldToScreen(
  x: number,
  y: number,
  viewport: YardViewportState,
) {
  return {
    x: x * viewport.scale + viewport.offsetX,
    y: y * viewport.scale + viewport.offsetY,
  }
}

export function screenToWorld(
  x: number,
  y: number,
  viewport: YardViewportState,
) {
  return {
    x: (x - viewport.offsetX) / viewport.scale,
    y: (y - viewport.offsetY) / viewport.scale,
  }
}

export function getVisibleSlots(
  slots: YardWorldSlot[],
  viewport: YardViewportState,
) {
  const padding = 160 / viewport.scale
  const left =
    -viewport.offsetX / viewport.scale -
    padding
  const top =
    -viewport.offsetY / viewport.scale -
    padding
  const right =
    left + viewport.width / viewport.scale +
    padding * 2
  const bottom =
    top + viewport.height / viewport.scale +
    padding * 2

  return slots.filter((slot) => {
    const slotRight = slot.x + slot.width
    const slotBottom = slot.y + slot.height

    return (
      slotRight >= left &&
      slot.x <= right &&
      slotBottom >= top &&
      slot.y <= bottom
    )
  })
}

export function clampScale(scale: number) {
  return Math.min(Math.max(scale, 0.18), 4)
}

export interface YardVisualizationSnapshot
  extends YardSnapshot {
  payload?: {
    zones?: Array<{
      id: string
      code: string
      name: string
      originX?: number
      originY?: number
      width?: number
      height?: number
      slots?: Array<{
        id: string
        code: string
        zoneId: string
        x: number
        y: number
        width?: number
        height?: number
        currentStackLevel?: number
        maxStackLevel?: number
        status?: string
      }>
    }>
  }
}

