export const useAuthStore =
  create<AuthStore>((set) => ({
    user: null,

    accessToken: getAccessToken(),
    refreshToken: getRefreshToken(),
    token: getAccessToken(),

    setSession: ({
      accessToken,
      refreshToken,
      user,
    }) => {
      setTokens({
        accessToken,
        refreshToken,
      })

      set({
        accessToken,
        refreshToken,
        token: accessToken,
        user,
      })
    },

    setAuth: (
      token,
      user,
      refreshToken = '',
    ) => {
      setTokens({
        accessToken: token,
        refreshToken,
      })

      set({
        accessToken: token,
        refreshToken,
        token,
        user,
      })
    },

    setUser: (user) => {
      set({
        user,
      })
    },

    restore: (
      token,
      user,
      refreshToken,
    ) => {
      set({
        accessToken: token,
        refreshToken:
          refreshToken ||
          getRefreshToken(),
        token,
        user,
      })
    },

    clearSession: () => {
      clearTokens()

      set({
        accessToken: null,
        refreshToken: null,
        token: null,
        user: null,
      })
    },

    logout: () => {
      clearTokens()

      set({
        accessToken: null,
        refreshToken: null,
        token: null,
        user: null,
      })
    },
  }))

import { create } from 'zustand'

interface Notification {
  id: number
  message: string
}

interface NotificationStore {
  notifications:
    Notification[]

  addNotification: (
    message: string,
  ) => void
}

export const useNotificationStore =
  create<NotificationStore>(
    (set) => ({
      notifications:
        [],

      addNotification:
        (
          message,
        ) => {
          set(
            (state) => ({
              notifications:
                [
                  {
                    id:
                      Date.now(),
                    message,
                  },

                  ...state.notifications,
                ],
            }),
          )
        },
    }),
  )

